#include<bits/stdc++.h>
using namespace std;
int a[200010],b[200010],x[200010],flag[200010];
int fa[200010],du[200010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&a[i],&b[i]);
    }
    int k;
    scanf("%d",&k);
    for(int i=1;i<=k;i++)
    {
        scanf("%d",&x[i]);
        flag[x[i]]=1;
    }
    for(int i=1;i<=m;i++)
    {
        if(flag[i]==0)
        {
            merge(a[i],b[i]);
        }
    }
    for(int i=1;i<=k;i++)
    {
        du[find(a[x[i]])]++;
        du[find(b[x[i]])]++;
    }
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        if(du[i]%2!=0)
        {
            ans++;
        }
    }
    if(ans<=2)
    {
        printf("Yes");
    }
    else
    {
        printf("No");
    }
    return 0;
}
